/*
* @info Vector Issuing Logic
*
* @author VLSI Lab, EE dept., Democritus University of Thrace
*
*/
`ifdef MODEL_TECH
    `include "vstructs.sv"
`endif
module vis #(
    parameter int VECTOR_REGISTERS   = 32,
    parameter int VECTOR_LANES       = 8 ,
    parameter int DATA_WIDTH         = 32,
    parameter int VECTOR_TICKET_BITS = 4
) (
    input  logic                                                                       clk             ,
    input  logic                                                                       rst_n           ,
    output logic                                                                       is_idle_o       ,
    //Instruction In
    input  logic                                                                       valid_in        ,
    input  remapped_v_instr                                                            instr_in        ,
    output logic                                                                       ready_o         ,
    //Instruction Out
    output logic                                                                       valid_o         ,
    output to_vector_exec [            VECTOR_LANES-1:0]                               data_to_exec    ,
    output to_vector_exec_info                                                         info_to_exec    ,
    input  logic                                                                       ready_i         ,
    //Memory Unit read ports
    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               mem_addr_0      ,
    output logic          [ VECTOR_LANES*DATA_WIDTH-1:0]                               mem_data_0      ,
    output logic                                                                       mem_pending_0   ,
    output logic          [      VECTOR_TICKET_BITS-1:0]                               mem_ticket_0    ,
    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               mem_addr_1      ,
    output logic          [ VECTOR_LANES*DATA_WIDTH-1:0]                               mem_data_1      ,
    output logic                                                                       mem_pending_1   ,
    output logic          [      VECTOR_TICKET_BITS-1:0]                               mem_ticket_1    ,
    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               mem_addr_2      ,
    output logic          [ VECTOR_LANES*DATA_WIDTH-1:0]                               mem_data_2      ,
    output logic                                                                       mem_pending_2   ,
    output logic          [      VECTOR_TICKET_BITS-1:0]                               mem_ticket_2    ,
    //Memory Unit Probing port
    input  logic          [                         3:0][$clog2(VECTOR_REGISTERS)-1:0] mem_prb_reg_i   ,
    output logic          [                         3:0]                               mem_prb_locked_o,
    output logic          [                         3:0][      VECTOR_TICKET_BITS-1:0] mem_prb_ticket_o,
    //Memory Unit write port
    input  logic          [            VECTOR_LANES-1:0]                               mem_wr_en       ,
    input  logic          [      VECTOR_TICKET_BITS-1:0]                               mem_wr_ticket   ,
    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               mem_wr_addr     ,
    input  logic          [ VECTOR_LANES*DATA_WIDTH-1:0]                               mem_wr_data     ,
    //Unlock ports
    input  logic                                                                       unlock_en       ,
    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               unlock_reg_a    ,
    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               unlock_reg_b    ,
    input  logic          [      VECTOR_TICKET_BITS-1:0]                               unlock_ticket   ,
    //Forward Point #1
    input  logic          [            VECTOR_LANES-1:0]                               frw_a_en        ,
    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               frw_a_addr      ,
    input  logic          [            VECTOR_LANES-1:0][              DATA_WIDTH-1:0] frw_a_data      ,
    input  logic          [      VECTOR_TICKET_BITS-1:0]                               frw_a_ticket    ,
    //Forward Point #2
    input  logic          [            VECTOR_LANES-1:0]                               frw_b_en        ,
    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               frw_b_addr      ,
    input  logic          [            VECTOR_LANES-1:0][              DATA_WIDTH-1:0] frw_b_data      ,
    input  logic          [      VECTOR_TICKET_BITS-1:0]                               frw_b_ticket    ,
    //Writeback (Forward Point #3)
    input  logic          [            VECTOR_LANES-1:0]                               wr_en           ,
    input  logic          [$clog2(VECTOR_REGISTERS)-1:0]                               wr_addr         ,
    input  logic          [            VECTOR_LANES-1:0][              DATA_WIDTH-1:0] wr_data         ,
    input  logic          [      VECTOR_TICKET_BITS-1:0]                               wr_ticket
);

    localparam int TOTAL_ELEMENT_ADDR_WIDTH = $clog2(VECTOR_REGISTERS*VECTOR_LANES);
    localparam int ELEMENT_ADDR_WIDTH       = $clog2(VECTOR_LANES)                 ;
    localparam int VREG_ADDR_WIDTH          = $clog2(VECTOR_REGISTERS)             ;
    //=======================================================
    //Internal Status tracking
    //=======================================================
    logic [VECTOR_REGISTERS-1:0][VECTOR_TICKET_BITS-1:0] pending_ticket;
    logic [VECTOR_REGISTERS-1:0][VECTOR_TICKET_BITS-1:0] locked_ticket;
    logic [VECTOR_REGISTERS-1:0][VECTOR_LANES-1:0] pending, locked;
    logic [    VECTOR_LANES-1:0] vl_therm;
    logic [ VREG_ADDR_WIDTH-1:0] current_exp_loop  ;
    logic                        can_issue, can_issue_m;
    logic                        do_issue, output_ready;
    logic                        reconfig_instr, memory_instr;
    logic                        expansion_finished, maxvl_reached, vl_reached;
    logic                        exec_finished     ;
    logic                        do_reconfigure    ;
    logic                        pop               ;
    logic                        start_new_instr   ;
    logic                        instr_is_rdc      ;

    logic [$clog2(VECTOR_REGISTERS*VECTOR_LANES):0] total_remaining_elements;
    logic [VECTOR_LANES-1:0][DATA_WIDTH-1:0] data_1, data_2;
    logic [VREG_ADDR_WIDTH-1:0] src_1, src_2, dst, mask_src;
    logic [  VREG_ADDR_WIDTH:0] max_expansion;
    logic [   VECTOR_LANES-1:0] no_hazards, no_hazards_m;
    logic [   VECTOR_LANES-1:0] can_lock_sources, can_lock_destination;
    logic [   VECTOR_LANES-1:0] issue_masked, issue_m_masked;
    logic [   VECTOR_LANES-1:0] frw_a_src_1, frw_a_src_2;
    logic [   VECTOR_LANES-1:0] frw_b_src_1, frw_b_src_2;
    logic [   VECTOR_LANES-1:0] frw_c_src_1, frw_c_src_2;
    logic [   VECTOR_LANES-1:0] src1_ok, src2_ok, rdst_ok;
    logic [   VECTOR_LANES-1:0] valid_output;
    logic [   VECTOR_LANES-1:0] mask;

    //Check if instr is memory operation
    assign memory_instr   = valid_in ? |instr_in.lock : 1'b0;
    //Check if instr is reconfiguration operation
    assign reconfig_instr = valid_in ? instr_in.reconfigure : 1'b0;

    assign start_new_instr = do_issue & ~|current_exp_loop;

    //Do reconfiguration
    assign do_reconfigure = reconfig_instr & valid_in & exec_finished;
    assign exec_finished  = ~(|pending) & ~(|locked);

    //Check if instr expansion finished
    assign total_remaining_elements = instr_in.vl - (current_exp_loop*VECTOR_LANES);
    assign expansion_finished       = maxvl_reached | vl_reached;
    assign maxvl_reached            = (current_exp_loop === (max_expansion-1));
    assign vl_reached               = (((current_exp_loop+1) << $clog2(VECTOR_LANES)) >= instr_in.vl);

    //Check if the EX is ready to accept (only those that you need to send to)
    assign output_ready = ready_i;
    assign vl_therm     = ~('1 << total_remaining_elements);

    assign do_issue = memory_instr ? (valid_in & can_issue_m)     :
                                     (valid_in & output_ready & can_issue);

    assign pop          = valid_in & ready_o;
    assign valid_output = vl_therm & {VECTOR_LANES{do_issue}} & {VECTOR_LANES{~memory_instr}} & {VECTOR_LANES{~reconfig_instr}};

    assign ready_o = reconfig_instr ? exec_finished                                   :
                     memory_instr   ? (can_issue_m & expansion_finished)              :
                     valid_in       ? (can_issue & expansion_finished & output_ready) : 1'b0;

    //Track Instruction Expansion
    always_ff @(posedge clk or negedge rst_n) begin : ExpansionTracker
        if(~rst_n) begin
            current_exp_loop <= '0;
        end else begin
            if (do_reconfigure | pop) begin
                current_exp_loop <= '0;
            end else if (do_issue) begin
                current_exp_loop <= current_exp_loop +1;
            end
        end
    end

    //Store the max expansion per instruction
    always_ff @(posedge clk or negedge rst_n) begin : maxExp
        if(~rst_n) begin
            max_expansion <= instr_in.maxvl >> $clog2(VECTOR_LANES);
        end else if(do_reconfigure) begin
            max_expansion <= instr_in.maxvl >> $clog2(VECTOR_LANES);
        end
    end

    // Struct containing control flow signals
    assign valid_o              = |valid_output;
    assign info_to_exec.fu      = instr_in.fu;
    assign info_to_exec.microop = instr_in.microop;
    assign info_to_exec.ticket  = instr_in.ticket;
    assign info_to_exec.dst     = dst;
    assign info_to_exec.head_uop= start_new_instr;
    assign info_to_exec.end_uop = expansion_finished;
    // We indicate the remaining VL here, so that the info can be used in EX
    assign info_to_exec.vl      = start_new_instr ? instr_in.vl : total_remaining_elements;

    assign mask_src = instr_in.mask_src + current_exp_loop;

    assign instr_is_rdc = (instr_in.fu == 2'b10) & (instr_in.microop[6:5] == 7'b10);

    //Create the src/dst identifiers
    // For reductions we trick the destination pointer. We need a result only on element#0 of the base register,
    // but the result will be ready on the last uop, normally pointing to the last register allocated. For this reason
    // we offset all the destination by +1, expect the last uop which will point to the base register, covering that way the
    // whole range, while storing the result in the correct location in the RF
    always_comb begin
        if (instr_is_rdc) begin
            if (expansion_finished & ~|current_exp_loop) begin // first & last uop, vl < vector_lanes
                dst   = instr_in.dst  + current_exp_loop;
                src_1 = instr_in.src1 + current_exp_loop;
                src_2 = instr_in.src2 + current_exp_loop;
            end else if (expansion_finished) begin             // last uop
                dst   = instr_in.dst;
                src_1 = instr_in.src1;
                src_2 = instr_in.src2;
            end else if (start_new_instr) begin                // first uop, vl > vector_lanes
                dst   = instr_in.dst  + current_exp_loop +1;
                src_1 = instr_in.src1 + current_exp_loop +1;
                src_2 = instr_in.src2 + current_exp_loop +1;
            end else begin                                     // middle uops
                dst   = instr_in.dst  + current_exp_loop +1;
                src_1 = instr_in.src1 + current_exp_loop +1;
                src_2 = instr_in.src2 + current_exp_loop +1;
            end
        end else begin
            dst   = instr_in.dst  + current_exp_loop;
            src_1 = instr_in.src1 + current_exp_loop;
            src_2 = instr_in.src2 + current_exp_loop;
        end
    end

    // Struct containing Data
    generate for (genvar k = 0; k < VECTOR_LANES; k++) begin: g_data_selection
        assign data_to_exec[k].valid     = valid_output[k];
        assign data_to_exec[k].immediate = instr_in.immediate;
        //DATA 1 Selection
        assign data_to_exec[k].data1  = ({32{frw_a_src_1[k]}}     & frw_a_data[k]) |
                                        ({32{frw_b_src_1[k]}}     & frw_b_data[k]) |
                                        ({32{frw_c_src_1[k]}}     & wr_data[k])    |
                                        ({32{~pending[src_1][k]}} & data_1[k]);
        //DATA 2 Selection
        assign data_to_exec[k].data2  = ({32{frw_a_src_2[k]}}     & frw_a_data[k]) |
                                        ({32{frw_b_src_2[k]}}     & frw_b_data[k]) |
                                        ({32{frw_c_src_2[k]}}     & wr_data[k])    |
                                        ({32{~pending[src_2][k]}} & data_2[k]);

        // Reductions mask all the elements for all the uops, except element#0 for the last uop
        assign data_to_exec[k].mask   = (instr_is_rdc & expansion_finished) ? (k == 0)   : // only element#0 of last uop will writeback a result
                                        (instr_is_rdc)                      ?  1'b0      : // no middle uop will write a result
                                        (instr_in.use_mask == 2'b10)        ? mask[k]    : // Use v1’s elements lsb as the mask
                                        (instr_in.use_mask == 2'b11)        ? ~mask[k]   : // Use ~v1’s elements lsb as the mask
                                                                               1'b1;       // No masking (== assume masking is 0xFFFF…FFFF)

    end endgenerate

    //Forwarding Logic
    generate for (genvar j = 0; j < VECTOR_LANES; j++) begin: g_frw_en
        //Forward Point #1
        assign frw_a_src_1[j] = frw_a_en[j] & (frw_a_addr === src_1) & (frw_a_ticket === pending_ticket[src_1]);
        assign frw_a_src_2[j] = frw_a_en[j] & (frw_a_addr === src_2) & (frw_a_ticket === pending_ticket[src_2]);
        //Forward Point #2
        assign frw_b_src_1[j] = frw_b_en[j] & (frw_b_addr === src_1) & (frw_b_ticket === pending_ticket[src_1]);
        assign frw_b_src_2[j] = frw_b_en[j] & (frw_b_addr === src_2) & (frw_b_ticket === pending_ticket[src_2]);
        //Forward Point #3 (Writeback)
        assign frw_c_src_1[j] = wr_en[j] & (wr_addr === src_1) & (wr_ticket === pending_ticket[src_1]);
        assign frw_c_src_2[j] = wr_en[j] & (wr_addr === src_2) & (wr_ticket === pending_ticket[src_2]);
    end endgenerate

    //Issue Logic -> non-Memory Instructions
    assign can_issue    = &issue_masked;
    assign issue_masked = no_hazards | ~vl_therm;
    generate for (genvar p = 0; p < VECTOR_LANES; p++) begin: g_iss_logic
        //src1
        assign src1_ok[p] = (instr_in.src1_iszero)                             |
                            (frw_a_src_1[p] | frw_b_src_1[p] | frw_c_src_1[p]) |
                            (~pending[src_1][p]);
        //src2
        assign src2_ok[p] = (instr_in.src2_iszero)                             |
                            (frw_a_src_2[p] | frw_b_src_2[p] | frw_c_src_2[p]) |
                            (~pending[src_2][p]);
        //dst
        assign rdst_ok[p]    = ~locked[dst][p];
        assign no_hazards[p] = src1_ok[p] & src2_ok[p] & rdst_ok[p];
    end endgenerate
    //Issue Logic -> Memory Instructions
    assign can_issue_m    = &issue_m_masked;
    assign issue_m_masked = no_hazards_m | ~vl_therm;

    generate for (genvar l = 0; l < VECTOR_LANES; l++) begin: g_iss_logic_mem
        assign can_lock_sources[l]     = instr_in.lock[0] ? (~locked[src_1][l] & ~locked[src_2][l]) : 1'b1;
        assign can_lock_destination[l] = instr_in.lock[1] ? ~locked[dst][l] : 1'b1;
        assign no_hazards_m[l]         = can_lock_sources[l] & can_lock_destination[l];
    end endgenerate

    //Convert to OH
    logic [VECTOR_LANES-1:0][VECTOR_REGISTERS-1:0] wr_addr_oh, mem_wr_addr_oh;
    logic [VECTOR_REGISTERS-1:0] dst_oh, src1_oh, src2_oh, unlock_reg_a_oh, unlock_reg_b_oh;

    assign dst_oh          = (1 << dst);
    assign src1_oh         = (1 << src_1);
    assign src2_oh         = (1 << src_2);
    assign unlock_reg_a_oh = (1 << unlock_reg_a);
    assign unlock_reg_b_oh = (1 << unlock_reg_b);

    generate for (genvar m = 0; m < VECTOR_LANES; m++) begin: g_oh_pntrs
        assign wr_addr_oh[m]     = (1 << wr_addr);
        assign mem_wr_addr_oh[m] = (1 << mem_wr_addr);
    end endgenerate

    //Pending status per elem/vreg
    logic ticket_match_pending    ;
    logic mem_ticket_match_pending;

    assign mem_ticket_match_pending = (mem_wr_ticket === pending_ticket[mem_wr_addr]);
    assign ticket_match_pending     = (wr_ticket     === pending_ticket[wr_addr]);

    always_ff @(posedge clk or negedge rst_n) begin: StatusPending
        if(!rst_n) begin
            pending <= '0;
        end else begin
            if(do_reconfigure) begin
                pending <= '0;
            end else if (!reconfig_instr) begin
                for (int k = 0; k < VECTOR_LANES; k++) begin
                    for (int i = 0; i < VECTOR_REGISTERS; i++) begin
                        if(dst_oh[i] && vl_therm[k] && do_issue && !instr_in.dst_iszero) begin
                            pending[i][k]     <= 1;
                            pending_ticket[i] <= instr_in.ticket;
                        end else if(dst_oh[i] && ~vl_therm[k] && do_issue && !instr_in.dst_iszero) begin
                            pending[i][k]     <= 0;
                        end else if(wr_en[k] && wr_addr_oh[k][i] && ticket_match_pending) begin
                            pending[i][k] <= 0;
                        end else if (mem_wr_en[k] && mem_wr_addr_oh[k][i] && mem_ticket_match_pending) begin
                            pending[i][k] <= 0;
                        end
                    end
                end
            end
        end
    end

    //Locked status per elem/vreg
    logic ticket_match_locked;
    assign ticket_match_locked = (unlock_ticket === locked_ticket[unlock_reg_a]);

    always_ff @(posedge clk or negedge rst_n) begin: StatusLocked
        if(!rst_n) begin
            locked <= '0;
        end else begin
            for (int k = 0; k < VECTOR_LANES; k++) begin
                for (int i = 0; i < VECTOR_REGISTERS; i++) begin
                    if(do_issue && vl_therm[k] && dst_oh[i] && instr_in.lock[1] && !instr_in.dst_iszero) begin
                        locked[i][k]     <= 1;
                        locked_ticket[i] <= instr_in.ticket;
                    // end else if(do_issue && vl_therm[k] && src1_oh[i] && instr_in.lock[0] && !instr_in.src1_iszero) begin // for now mem ops dont use src1
                    //     locked[i][k]     <= 1;                                                                            // and dont release src1, might change
                    //     locked_ticket[i] <= instr_in.ticket;
                    end else if(do_issue && vl_therm[k] && src2_oh[i] && instr_in.lock[0] && !instr_in.src2_iszero) begin
                        locked[i][k]     <= 1;
                        locked_ticket[i] <= instr_in.ticket;
                    end else if(unlock_en && unlock_reg_a_oh[i] && ticket_match_locked) begin
                        locked[i][k] <= 0;
                    end else if(unlock_en && unlock_reg_b_oh[i] && ticket_match_locked) begin
                        locked[i][k] <= 0;
                    end
                end
            end
        end
    end

    assign mem_pending_0 = pending[mem_addr_0][0];
    assign mem_ticket_0  = pending_ticket[mem_addr_0];
    assign mem_pending_1 = pending[mem_addr_1][0];
    assign mem_ticket_1  = pending_ticket[mem_addr_1];
    assign mem_pending_2 = pending[mem_addr_2][0];
    assign mem_ticket_2  = pending_ticket[mem_addr_2];

    generate
        for (genvar i = 0; i < 4; i++) begin
            assign mem_prb_locked_o[i] = locked[mem_prb_reg_i[i]][0];
            assign mem_prb_ticket_o[i] = locked_ticket[mem_prb_reg_i[i]];
        end
    endgenerate
    //Mask the writebacks
    logic [VECTOR_LANES-1:0] wr_en_masked;
    always_comb begin : WBmask
        for (int i = 0; i < VECTOR_LANES; i++) begin
            wr_en_masked[i] = wr_en[i] & ~locked[wr_addr][i];
        end
    end
    // Vector Register File
    vrf #(
        .VREGS     (VECTOR_REGISTERS),
        .ELEMENTS  (VECTOR_LANES    ),
        .DATA_WIDTH(DATA_WIDTH      )
    ) vrf (
        .clk         (clk         ),
        .reset       (do_reconfigure), // state resetted during reconfiguration
        //Read Ports
        .rd_addr_1   (src_1       ),
        .data_out_1  (data_1      ),
        .rd_addr_2   (src_2       ),
        .data_out_2  (data_2      ),
        .mask_src    (mask_src    ),
        .mask        (mask        ),
        //Element Write Ports (per element enabled)
        .el_wr_en    (wr_en_masked),
        .el_wr_addr  (wr_addr     ),
        .el_wr_data  (wr_data     ),
        //Register Read Port
        .v_rd_addr_0 (mem_addr_0  ),
        .v_data_out_0(mem_data_0  ),
        .v_rd_addr_1 (mem_addr_1  ),
        .v_data_out_1(mem_data_1  ),
        .v_rd_addr_2 (mem_addr_2  ),
        .v_data_out_2(mem_data_2  ),
        //Register Write Port (per element enabled)
        .v_wr_en     (mem_wr_en   ),
        .v_wr_addr   (mem_wr_addr ),
        .v_wr_data   (mem_wr_data )
    );

    assign is_idle_o = ~valid_in & ~|pending & ~|locked;
    //=======================================================
    // Performance Stats
    //=======================================================
    logic [63:0] total_cycles, total_issues, total_idle;
    logic [63:0] idle_no_valid, stall_pending, stall_locked;
    logic no_pending;

    assign no_pending = &(src1_ok & src2_ok);
    always_ff @(posedge clk or negedge rst_n) begin: perf_mon
        if(~rst_n) begin
            total_cycles  <= '0;
            total_issues  <= '0;
            total_idle    <= '0;
            idle_no_valid <= '0;
            stall_pending <= '0;
            stall_locked  <= '0;
        end else begin
            total_cycles <= total_cycles +1;
            if (do_issue)                           total_issues  <= total_issues  +1;
            if (!do_issue)                          total_idle    <= total_idle    +1;
            if (ready_i && !valid_in)               idle_no_valid <= idle_no_valid +1;
            if (ready_i && valid_in && !no_pending) stall_pending <= stall_pending +1;
            if (ready_i && valid_in && !(&rdst_ok)) stall_locked  <= stall_locked  +1;
        end
    end

`ifdef MODEL_TECH
    `include "vis_sva.sv"
`endif

endmodule

/*
* @info Vector Memory Unit
*
* @author VLSI Lab, EE dept., Democritus University of Thrace
*
*/
`ifdef MODEL_TECH
    `include "vstructs.sv"
`endif
module vmu #(
    parameter int REQ_DATA_WIDTH     = 256,
    parameter int VECTOR_REGISTERS   = 32 ,
    parameter int VECTOR_LANES       = 8  ,
    parameter int DATA_WIDTH         = 32 ,
    parameter int ADDR_WIDTH         = 32 ,
    parameter int MICROOP_WIDTH      = 5  ,
    parameter int VECTOR_TICKET_BITS = 4
) (
    input  logic                                                              clk                ,
    input  logic                                                              rst_n              ,
    output logic                                                              vmu_idle_o         ,
    //Instruction In
    input  logic                                                              valid_in           ,
    input  memory_remapped_v_instr                                            instr_in           ,
    output logic                                                              ready_o            ,
    //Cache Interface (OUT)
    output logic                                                              mem_req_valid_o    ,
    output vector_mem_req                                                     mem_req_o          ,
    //Cache Interface (IN)
    input  logic                                                              cache_ready_i      ,
    input  logic                                                              mem_resp_valid_i   ,
    input  vector_mem_resp                                                    mem_resp_i         ,
    //RF Interface - Loads
    output logic [$clog2(VECTOR_REGISTERS)-1:0]                               rd_addr_0_o        ,
    input  logic [ VECTOR_LANES*DATA_WIDTH-1:0]                               rd_data_0_i        ,
    input  logic                                                              rd_pending_0_i     ,
    input  logic [      VECTOR_TICKET_BITS-1:0]                               rd_ticket_0_i      ,
    //RF Interface - Stores
    output logic [$clog2(VECTOR_REGISTERS)-1:0]                               rd_addr_1_o        ,
    input  logic [ VECTOR_LANES*DATA_WIDTH-1:0]                               rd_data_1_i        ,
    input  logic                                                              rd_pending_1_i     ,
    input  logic [      VECTOR_TICKET_BITS-1:0]                               rd_ticket_1_i      ,
    output logic [$clog2(VECTOR_REGISTERS)-1:0]                               rd_addr_2_o        ,
    input  logic [ VECTOR_LANES*DATA_WIDTH-1:0]                               rd_data_2_i        ,
    input  logic                                                              rd_pending_2_i     ,
    input  logic [      VECTOR_TICKET_BITS-1:0]                               rd_ticket_2_i      ,
    //RF Writeback Interface
    output logic [            VECTOR_LANES-1:0]                               wrtbck_en_o        ,
    output logic [$clog2(VECTOR_REGISTERS)-1:0]                               wrtbck_reg_o       ,
    output logic [ VECTOR_LANES*DATA_WIDTH-1:0]                               wrtbck_data_o      ,
    output logic [      VECTOR_TICKET_BITS-1:0]                               wrtbck_ticket_o    ,
    //RF Writeback Probing Interface
    output logic [                         3:0][$clog2(VECTOR_REGISTERS)-1:0] wrtbck_prb_reg_o   ,
    input  logic [                         3:0]                               wrtbck_prb_locked_i,
    input  logic [                         3:0][      VECTOR_TICKET_BITS-1:0] wrtbck_prb_ticket_i,
    //Unlock Interface
    output logic                                                              unlock_en_o        ,
    output logic [$clog2(VECTOR_REGISTERS)-1:0]                               unlock_reg_a_o     ,
    output logic [$clog2(VECTOR_REGISTERS)-1:0]                               unlock_reg_b_o     ,
    output logic [      VECTOR_TICKET_BITS-1:0]                               unlock_ticket_o
);

    //=======================================================
    // WIRES
    //=======================================================
    logic                                load_unlock_en    ;
    logic [$clog2(VECTOR_REGISTERS)-1:0] load_unlock_reg_a ;
    logic [$clog2(VECTOR_REGISTERS)-1:0] load_unlock_reg_b ;
    logic [      VECTOR_TICKET_BITS-1:0] load_unlock_ticket;
    logic [              ADDR_WIDTH-1:0] load_start_addr   ;
    logic [              ADDR_WIDTH-1:0] load_end_addr     ;
    logic [              ADDR_WIDTH-1:0] load_req_addr     ;
    logic [           MICROOP_WIDTH-1:0] load_req_microop  ;
    logic [  $clog2(REQ_DATA_WIDTH/8):0] load_req_size     ;
    logic [      $clog2(VECTOR_LANES):0] load_req_ticket   ;
    logic                                ld_can_inteleave  ;
    logic [            VECTOR_LANES-1:0] ld_wb_en          ;
    logic [$clog2(VECTOR_REGISTERS)-1:0] ld_wb_reg         ;
    logic [ VECTOR_LANES*DATA_WIDTH-1:0] ld_wb_data        ;
    logic [      VECTOR_TICKET_BITS-1:0] ld_wb_ticket      ;

    logic                                store_unlock_en    ;
    logic [$clog2(VECTOR_REGISTERS)-1:0] store_unlock_reg_a ;
    logic [$clog2(VECTOR_REGISTERS)-1:0] store_unlock_reg_b ;
    logic [      VECTOR_TICKET_BITS-1:0] store_unlock_ticket;
    logic [              ADDR_WIDTH-1:0] store_start_addr   ;
    logic [              ADDR_WIDTH-1:0] store_end_addr     ;
    logic [              ADDR_WIDTH-1:0] store_req_addr     ;
    logic [           MICROOP_WIDTH-1:0] store_req_microop  ;
    logic [  $clog2(REQ_DATA_WIDTH/8):0] store_req_size     ;
    logic [          REQ_DATA_WIDTH-1:0] store_req_data     ;
    logic                                st_can_interleave  ;

    logic                                toepl_unlock_en    ;
    logic [$clog2(VECTOR_REGISTERS)-1:0] toepl_unlock_reg_a ;
    logic [$clog2(VECTOR_REGISTERS)-1:0] toepl_unlock_reg_b ;
    logic [      VECTOR_TICKET_BITS-1:0] toepl_unlock_ticket;
    logic [              ADDR_WIDTH-1:0] toepl_req_addr     ;
    logic [           MICROOP_WIDTH-1:0] toepl_req_microop  ;
    logic [  $clog2(REQ_DATA_WIDTH/8):0] toepl_req_size     ;
    logic [      $clog2(VECTOR_LANES):0] toepl_req_ticket   ;
    logic [            VECTOR_LANES-1:0] tp_wb_en           ;
    logic [$clog2(VECTOR_REGISTERS)-1:0] tp_wb_reg          ;
    logic [ VECTOR_LANES*DATA_WIDTH-1:0] tp_wb_data         ;
    logic [      VECTOR_TICKET_BITS-1:0] tp_wb_ticket       ;

    logic [1:0] wb_grant    ;
    logic [1:0] wb_request  ;
    logic [2:0] is_busy     ;
    logic [1:0] tail        ;
    logic       fifo_ready  ;
    logic       is_load     ;
    logic       is_store    ;
    logic       is_toepl    ;
    logic       is_reconf   ;
    logic       push_load   ;
    logic       push_store  ;
    logic       push_toepl  ;
    logic       load_ready  ;
    logic       store_ready ;
    logic       toepl_ready ;
    logic       load_starts ;
    logic       store_starts;
    logic       toepl_starts;
    logic       load_ends   ;
    logic       store_ends  ;
    logic       toepl_ends  ;
    logic       any_request ;
    logic       any_grant   ;
    logic       ld_grant    ;
    logic       st_grant    ;
    logic       tp_grant    ;
    //Create the ready out signal
    assign ready_o = valid_in & is_load  ? (load_ready  & fifo_ready) :
                     valid_in & is_store ? (store_ready & fifo_ready) :
                     valid_in & is_toepl ? (toepl_ready & fifo_ready) :
                                           (load_ready & store_ready & toepl_ready & fifo_ready);

    assign vmu_idle_o = ~|is_busy;

    //Pick the Outputs
    assign unlock_en_o     = load_unlock_en | store_unlock_en | toepl_unlock_en;

    assign unlock_reg_a_o  = wb_grant[1]    ? toepl_unlock_reg_a  :
                             load_unlock_en ? load_unlock_reg_a   :
                                              store_unlock_reg_a;

    assign unlock_reg_b_o  = wb_grant[1]    ? toepl_unlock_reg_b  :
                             load_unlock_en ? load_unlock_reg_b   :
                                              store_unlock_reg_b;

    assign unlock_ticket_o = wb_grant[1]    ? toepl_unlock_ticket :
                             load_unlock_en ? load_unlock_ticket  :
                                              store_unlock_ticket;

    assign mem_req_valid_o   = any_grant;
    assign mem_req_o.address = ld_grant ? load_req_addr     :
                               st_grant ? store_req_addr    :
                                          toepl_req_addr;

    assign mem_req_o.microop = ld_grant ? load_req_microop  :
                               st_grant ? store_req_microop :
                                          toepl_req_microop;

    assign mem_req_o.size    = ld_grant ? load_req_size     :
                               st_grant ? store_req_size    :
                                          toepl_req_size;

    assign mem_req_o.ticket  = ld_grant ? load_req_ticket   :
                                          toepl_req_ticket;

    assign mem_req_o.data    = store_req_data;

    assign wrtbck_en_o     = wb_grant[0] ? ld_wb_en     : tp_wb_en;
    assign wrtbck_reg_o    = wb_grant[0] ? ld_wb_reg    : tp_wb_reg;
    assign wrtbck_data_o   = wb_grant[0] ? ld_wb_data   : tp_wb_data;
    assign wrtbck_ticket_o = wb_grant[0] ? ld_wb_ticket : tp_wb_ticket;

    //Push the instruction to the correct engine
    assign is_load   = ~instr_in.reconfigure & instr_in.microop[`LD_BIT]  & ~is_toepl;
    assign is_store  = ~instr_in.reconfigure & ~instr_in.microop[`LD_BIT] & ~is_toepl;
    assign is_toepl  = ~instr_in.reconfigure & (instr_in.microop === 7'b1110011 | instr_in.microop === 7'b1010011);
    assign is_reconf =  instr_in.reconfigure;

    always_comb begin
        if(is_reconf) begin //reconfiguration must happen simultaneously
            push_load  = valid_in & load_ready & store_ready & toepl_ready;
            push_store = valid_in & load_ready & store_ready & toepl_ready;
            push_toepl = valid_in & load_ready & store_ready & toepl_ready;
        end else begin
            push_load  = valid_in & is_load  & load_ready  & fifo_ready;
            push_store = valid_in & is_store & store_ready & fifo_ready;
            push_toepl = valid_in & is_toepl & toepl_ready & fifo_ready;
        end
    end

    // LOAD ENGINE
    vmu_ld_eng #(
        .REQ_DATA_WIDTH    (REQ_DATA_WIDTH    ),
        .VECTOR_REGISTERS  (VECTOR_REGISTERS  ),
        .VECTOR_LANES      (VECTOR_LANES      ),
        .DATA_WIDTH        (DATA_WIDTH        ),
        .ADDR_WIDTH        (ADDR_WIDTH        ),
        .MICROOP_WIDTH     (MICROOP_WIDTH     ),
        .VECTOR_TICKET_BITS(VECTOR_TICKET_BITS)
    ) vmu_ld_eng (
        .clk                (clk                   ),
        .rst_n              (rst_n                 ),
        //input Interface
        .valid_in           (push_load             ),
        .instr_in           (instr_in              ),
        .ready_o            (load_ready            ),
        //RF read Interface (for indexed stride)
        .rd_addr_o          (rd_addr_0_o           ),
        .rd_data_i          (rd_data_0_i           ),
        .rd_pending_i       (rd_pending_0_i        ),
        .rd_ticket_i        (rd_ticket_0_i         ),
        //RF write Interface
        .wrtbck_grant_i     (wb_grant[0]           ),
        .wrtbck_req_o       (wb_request[0]         ),
        .wrtbck_en_o        (ld_wb_en              ),
        .wrtbck_reg_o       (ld_wb_reg             ),
        .wrtbck_data_o      (ld_wb_data            ),
        .wrtbck_ticket_o    (ld_wb_ticket          ),
        //RF Writeback Probing Interface
        .wrtbck_reg_a_o     (wrtbck_prb_reg_o[0]   ),
        .wrtbck_locked_a_i  (wrtbck_prb_locked_i[0]),
        .wrtbck_ticket_a_i  (wrtbck_prb_ticket_i[0]),
        .wrtbck_reg_b_o     (wrtbck_prb_reg_o[1]   ),
        .wrtbck_locked_b_i  (wrtbck_prb_locked_i[1]),
        .wrtbck_ticket_b_i  (wrtbck_prb_ticket_i[1]),
        //Unlock Interface
        .unlock_en_o        (load_unlock_en        ),
        .unlock_reg_a_o     (load_unlock_reg_a     ),
        .unlock_reg_b_o     (load_unlock_reg_b     ),
        .unlock_ticket_o    (load_unlock_ticket    ),
        //Request Interface
        .grant_i            (ld_grant              ),
        .req_en_o           (ld_request            ),
        .req_addr_o         (load_req_addr         ),
        .req_microop_o      (load_req_microop      ),
        .req_size_o         (load_req_size         ),
        .req_ticket_o       (load_req_ticket       ),
        // Incoming Data from Cache
        .resp_valid_i       (mem_resp_valid_i      ),
        .resp_ticket_i      (mem_resp_i.ticket     ),
        .resp_size_i        (mem_resp_i.size       ),
        .resp_data_i        (mem_resp_i.data       ),
        //Sync Interface
        .is_busy_o          (is_busy[0]            ),
        .can_be_inteleaved_o(ld_can_inteleave      ),
        .start_addr_o       (load_start_addr       ),
        .end_addr_o         (load_end_addr         )
    );
    //STORE ENGINE
    vmu_st_eng #(
        .REQ_DATA_WIDTH    (REQ_DATA_WIDTH    ),
        .VECTOR_REGISTERS  (VECTOR_REGISTERS  ),
        .VECTOR_LANES      (VECTOR_LANES      ),
        .DATA_WIDTH        (DATA_WIDTH        ),
        .ADDR_WIDTH        (ADDR_WIDTH        ),
        .MICROOP_WIDTH     (MICROOP_WIDTH     ),
        .VECTOR_TICKET_BITS(VECTOR_TICKET_BITS)
    ) vmu_st_eng (
        .clk                (clk                ),
        .rst_n              (rst_n              ),
        //Input Interface
        .valid_in           (push_store         ),
        .instr_in           (instr_in           ),
        .ready_o            (store_ready        ),
        //RF Interface (per vreg)
        .rd_addr_1_o        (rd_addr_1_o        ),
        .rd_data_1_i        (rd_data_1_i        ),
        .rd_pending_1_i     (rd_pending_1_i     ),
        .rd_ticket_1_i      (rd_ticket_1_i      ),
        //RF Interface (for indexed stride)
        .rd_addr_2_o        (rd_addr_2_o        ),
        .rd_data_2_i        (rd_data_2_i        ),
        .rd_pending_2_i     (rd_pending_2_i     ),
        .rd_ticket_2_i      (rd_ticket_2_i      ),
        //Unlock Interface
        .unlock_en_o        (store_unlock_en    ),
        .unlock_reg_a_o     (store_unlock_reg_a ),
        .unlock_reg_b_o     (store_unlock_reg_b ),
        .unlock_ticket_o    (store_unlock_ticket),
        //Request Interface
        .req_en_o           (st_request         ),
        .grant_i            (st_grant           ),
        .req_addr_o         (store_req_addr     ),
        .req_microop_o      (store_req_microop  ),
        .req_size_o         (store_req_size     ),
        .req_data_o         (store_req_data     ),
        //Sync Interface
        .can_be_inteleaved_o(st_can_interleave  ),
        .is_busy_o          (is_busy[1]         ),
        .start_addr_o       (store_start_addr   ),
        .end_addr_o         (store_end_addr     )
    );
    //TOEPLITZ PREFETCHER
    vmu_tp_eng #(
        .REQ_DATA_WIDTH    (REQ_DATA_WIDTH    ),
        .VECTOR_REGISTERS  (VECTOR_REGISTERS  ),
        .VECTOR_LANES      (VECTOR_LANES      ),
        .DATA_WIDTH        (DATA_WIDTH        ),
        .ADDR_WIDTH        (ADDR_WIDTH        ),
        .MICROOP_WIDTH     (MICROOP_WIDTH     ),
        .VECTOR_TICKET_BITS(VECTOR_TICKET_BITS)
    ) vmu_tp_eng (
        .clk              (clk                   ),
        .rst_n            (rst_n                 ),
        //input Interface
        .valid_in         (push_toepl            ),
        .instr_in         (instr_in              ),
        .ready_o          (toepl_ready           ),
        //RF write Interface
        .wrtbck_grant_i   (wb_grant[1]           ),
        .wrtbck_req_o     (wb_request[1]         ),
        .wrtbck_en_o      (tp_wb_en              ),
        .wrtbck_reg_o     (tp_wb_reg             ),
        .wrtbck_data_o    (tp_wb_data            ),
        .wrtbck_ticket_o  (tp_wb_ticket          ),
        //RF Writeback Probing Interface
        .wrtbck_reg_a_o   (wrtbck_prb_reg_o[2]   ),
        .wrtbck_locked_a_i(wrtbck_prb_locked_i[2]),
        .wrtbck_ticket_a_i(wrtbck_prb_ticket_i[2]),
        .wrtbck_reg_b_o   (wrtbck_prb_reg_o[3]   ),
        .wrtbck_locked_b_i(wrtbck_prb_locked_i[3]),
        .wrtbck_ticket_b_i(wrtbck_prb_ticket_i[3]),
        //Unlock Interface
        .unlock_en_o      (toepl_unlock_en       ),
        .unlock_reg_a_o   (toepl_unlock_reg_a    ),
        .unlock_reg_b_o   (toepl_unlock_reg_b    ),
        .unlock_ticket_o  (toepl_unlock_ticket   ),
        //Request Interface
        .grant_i          (tp_grant              ),
        .req_en_o         (tp_request            ),
        .req_addr_o       (toepl_req_addr        ),
        .req_microop_o    (toepl_req_microop     ),
        .req_size_o       (toepl_req_size        ),
        .req_ticket_o     (toepl_req_ticket      ),
        // Incoming Data from Cache
        .resp_valid_i     (mem_resp_valid_i      ),
        .resp_ticket_i    (mem_resp_i.ticket     ),
        .resp_size_i      (mem_resp_i.size       ),
        .resp_data_i      (mem_resp_i.data       ),
        //Sync Interface
        .is_busy_o        (is_busy[2]            )
    );

    //=======================================================
    //Keep track of the oldest LD/TP instruction in the engine
    //and provide the grants for the writeback access
    //=======================================================
    logic [1:0] is_older               ;
    logic [1:0] nxt_is_older           ;
    logic [1:0] high_priority_grant    ;
    logic       any_high_priority_grant;
    logic       new_ld_starts          ;

    //Requests by the oldest instruction are considered high priority
    assign wb_grant = ({2{ any_high_priority_grant}} & high_priority_grant) |
                      ({2{~any_high_priority_grant}} & wb_request          );

    assign any_high_priority_grant = |high_priority_grant;
    assign high_priority_grant     = is_older & wb_request;

    assign new_ld_starts = push_load | push_toepl;
    always_ff @(posedge clk or negedge rst_n) begin
        if(~rst_n) begin
            is_older <= '0;
        end else if(new_ld_starts) begin
            is_older <= nxt_is_older;
        end
    end

    always_comb begin
        if(new_ld_starts) begin //new load started
            nxt_is_older = is_busy[2] ? 2'b10 : //the old toepl is the oldest
                                        2'b01;  //the new load is the oldest
        end else begin //new toepl started (or nothing started)
            nxt_is_older = is_busy[0] ? 2'b01 : //the old load is the oldest
                                        2'b10;  //the new toepl is the oldest
        end
    end

    //=======================================================
    //Keep track of the oldest instruction in the engine
    //and provide the grants for the memory access
    //=======================================================
    logic [1:0] push_data;
    logic [1:0] pop_data;
    logic push;
    logic pop;

    assign load_starts  =  push_load & ~push_store & ~push_toepl;
    assign store_starts = ~push_load &  push_store & ~push_toepl;
    assign toepl_starts = ~push_load & ~push_store &  push_toepl;

    assign load_ends    = ~is_busy[0];
    assign store_ends   = ~is_busy[1];
    assign toepl_ends   = ~is_busy[2];

    assign any_request = ld_request | st_request | tp_request;
    assign any_grant   = ld_grant   | st_grant   | tp_grant;

    assign push_data = load_starts  ? 2'b01 :
                       store_starts ? 2'b10 : 2'b11;
    assign push = load_starts | store_starts | toepl_starts;
    // keep active instructions in vMU
    fifo_duth #(
        .DW   (2),
        .DEPTH(3)
    ) fifo_duth (
        .clk      (clk       ),
        .rst      (~rst_n    ),
        .push_data(push_data ),
        .push     (push      ),
        .ready    (fifo_ready),
        .pop_data (pop_data  ),
        .valid    (valid     ),
        .pop      (pop       )
    );

    assign ld_grant =  valid & cache_ready_i & pop_data == 2'b01 & ld_request;
    assign st_grant =  valid & cache_ready_i & pop_data == 2'b10 & st_request;
    // prefetcher gets access to idle cycles as well
    assign tp_grant = (valid & cache_ready_i & pop_data == 2'b11 & tp_request) |
                      (~ld_grant & ~st_grant & cache_ready_i     & tp_request);

    assign pop      = (valid & pop_data == 2'b01 & load_ends)  |
                      (valid & pop_data == 2'b10 & store_ends) |
                      (valid & pop_data == 2'b11 & toepl_ends);


`ifdef MODEL_TECH
    `include "vmu_sva.sv"
`endif

endmodule

