1	/*
2	* @info Vector Register Remmaping
3	*
4	* @author VLSI Lab, EE dept., Democritus University of Thrace
5	*
6	*/
7	`ifdef MODEL_TECH
8	    `include "vstructs.sv"
9	`endif
10	module vrrm #(
11	    parameter int VECTOR_REGISTERS   = 32,
12	    parameter int VECTOR_LANES       = 8 ,
13	    parameter int VECTOR_TICKET_BITS = 4
14	) (
15	    input  logic                   clk        ,
16	    input  logic                   rst_n      ,
17	    output logic                   is_idle_o  ,
18	    //Instruction In
19	    input  logic                   valid_in   ,
20	    input  to_vector               instr_in   ,
21	    output logic                   pop_instr  ,
22	    //Instruction Out
23	    output logic                   valid_o    ,
24	    output remapped_v_instr        instr_out  ,
25	    input  logic                   ready_i    ,
26	    //Memory Instruction Out
27	    output logic                   m_valid_o  ,
28	    output memory_remapped_v_instr m_instr_out,
29	    input  logic                   m_ready_i
30	);
31	
32	    localparam int ELEM_ADDR_WIDTH = $clog2(VECTOR_LANES*32);
33	    localparam int REGISTER_BITS   = $clog2(VECTOR_REGISTERS);
34	
35	    logic [  VECTOR_REGISTERS-1:0][VECTOR_TICKET_BITS-1:0] last_producer      ;
36	    logic [     REGISTER_BITS-1:0]                         next_free_vreg     ;
37	    logic [     REGISTER_BITS-1:0]                         rdst_destination   ;
38	    logic [       REGISTER_BITS:0]                         vreg_hop           ;
39	    logic [     REGISTER_BITS-1:0]                         remapped_src1      ;
40	    logic [     REGISTER_BITS-1:0]                         remapped_src2      ;
41	    logic [VECTOR_TICKET_BITS-1:0]                         next_ticket        ;
42	    logic                                                  do_operation, do_remap, rdst_remapped;
43	    logic                                                  memory_instr       ;
44	    logic                                                  reconfig_instr     ;
45	    logic                                                  do_reconfigure     ;
46	    logic                                                  load_instr         ;
47	    logic                                                  toepl_instr        ;
48	    logic                                                  toepl_conf         ;
49	    logic                                                  last_producer_wr_en;
50	
51	    //Check for special types of instructions
52	    assign reconfig_instr = instr_in.reconfigure;                          // general reconfiguration instr
53	    assign memory_instr   = instr_in.fu === `MEM_FU;                       // memory instr
54	    assign toepl_conf     = instr_in.microop === 7'b1110011;               // toeplitz prefetcher configuration
55	    assign toepl_instr    = instr_in.microop === 7'b1010011 & ~toepl_conf; // toeplitz prefetcher instr
56	    assign load_instr     = instr_in.microop[`LD_BIT] & ~toepl_instr;      // load instr
57	    //Push Pop Signals
58	    assign valid_o      = valid_in & do_operation;
59	    assign do_operation = (memory_instr | reconfig_instr) ? (valid_in & ready_i & m_ready_i) : (valid_in & ready_i);
60	    assign pop_instr    = do_operation;
